     1→import { useCallback } from 'react';
     2→import { useSelector } from 'react-redux';
     3→import { getAcountNumber } from '../../../hooks/useSelectors';
     4→import { rewardsAccountSettingsService } from '../services';
     5→import { useRewardsAccountSettingsStore } from './useRewardsAccountSettingsStore';
     6→
     7→export function useRewardsAccountSettings() {
     8→  const accountId = useSelector(getAcountNumber);
     9→
    10→  const { hasRedeemedCashback, isLoading, isError } = useRewardsAccountSettingsStore(
    11→    (state) => state.rewardsAccountSettings
    12→  );
    13→
    14→  const { setHasRedeemedCashback, setLoading, setError } = useRewardsAccountSettingsStore(
    15→    (state) => state.rewardsAccountSettingsActions
    16→  );
    17→
    18→  const checkHasRedeemed = useCallback(
    19→    async ({ showLoading = false }: { showLoading?: boolean } = {}): Promise<boolean> => {
    20→      if (!accountId) {
    21→        return false;
    22→      }
    23→
    24→      if (showLoading) {
    25→        setLoading(true);
    26→      }
    27→
    28→      try {
    29→        const hasRedeemed = await rewardsAccountSettingsService.checkHasRedeemedCashback(accountId);
    30→        setHasRedeemedCashback(hasRedeemed);
    31→        return hasRedeemed;
    32→      } catch {
    33→        setError(true);
    34→        return false;
    35→      }
    36→    },
    37→    [accountId, setHasRedeemedCashback, setLoading, setError]
    38→  );
    39→
    40→  const markAsRedeemed = useCallback(async (): Promise<boolean> => {
    41→    if (!accountId) {
    42→      return false;
    43→    }
    44→
    45→    try {
    46→      await rewardsAccountSettingsService.markCashbackAsRedeemed(accountId);
    47→      setHasRedeemedCashback(true);
    48→      return true;
    49→    } catch {
    50→      return false;
    51→    }
    52→  }, [accountId, setHasRedeemedCashback]);
    53→
    54→  return {
    55→    hasRedeemedCashback,
    56→    isLoading,
    57→    isError,
    58→    checkHasRedeemed,
    59→    markAsRedeemed,
    60→  };
    61→}
