import type { StateCreator } from 'zustand';
import type { RewardsAccountSettingsActions, RewardsAccountSettingsState } from '../models';

export type RewardsAccountSettingsSlice = {
  rewardsAccountSettings: RewardsAccountSettingsState;
  rewardsAccountSettingsActions: RewardsAccountSettingsActions;
};

const initialState: RewardsAccountSettingsState = {
  hasRedeemedCashback: null,
  isLoading: false,
  isError: false,
};

export const createRewardsAccountSettingsSlice: StateCreator<
  RewardsAccountSettingsSlice,
  [],
  [],
  RewardsAccountSettingsSlice
> = (set) => ({
  rewardsAccountSettings: initialState,
  rewardsAccountSettingsActions: {
    setHasRedeemedCashback: (value) =>
      set((state) => ({
        rewardsAccountSettings: {
          ...state.rewardsAccountSettings,
          hasRedeemedCashback: value,
          isLoading: false,
          isError: false,
        },
      })),
    setLoading: (isLoading) =>
      set((state) => ({
        rewardsAccountSettings: {
          ...state.rewardsAccountSettings,
          isLoading,
          ...(isLoading && { isError: false }),
        },
      })),
    setError: (isError) =>
      set((state) => ({
        rewardsAccountSettings: {
          ...state.rewardsAccountSettings,
          isLoading: false,
          isError,
        },
      })),
    reset: () =>
      set({
        rewardsAccountSettings: initialState,
      }),
  },
});

