/**
 * Service to manage user settings in the rewards program.
 */

export type RewardsGetAccountSettingsParams = {
  accountNumber: string;
};

/** A record containing the account settings in the rewards program. */
export type RewardsAccountSettings = {
  invoiceCashbackRedemption?: {
    /** The date the redemption occurred. */
    redeemedAtDate: string | undefined;
  };
};

export interface RewardsAccountSettingsDocument {
  /** The account id (NRC) */
  codigoCliente: string;
  /** A record containing the account settings in the rewards program. */
  value: RewardsAccountSettings;
  /** Settings status: 1 means active; 0 means deactivated **/
  status: 0 | 1;
}

export interface RewardsAccountSettingsState {
  hasRedeemedCashback: boolean | null;
  isLoading: boolean;
  isError: boolean;
}

export interface RewardsAccountSettingsActions {
  setHasRedeemedCashback: (value: boolean) => void;
  setLoading: (isLoading: boolean) => void;
  setError: (isError: boolean) => void;
  reset: () => void;
}

