import api from '../../api';

import { RewardsAccountSettingsDocument, RewardsGetAccountSettingsParams } from '../models';

export class RewardsAccountSettingsApi {
  client = api;

  async consultAccountSettings(
    params: RewardsGetAccountSettingsParams
  ): Promise<RewardsAccountSettingsDocument> {
    const { accountNumber } = params;
    const { data } = await this.client.get('/rewardProgram/consult-permission', {
      headers: {
        codigoCliente: accountNumber,
      },
    });
    return data;
  }

  async upsertAccountSettings(
    document: RewardsAccountSettingsDocument
  ): Promise<RewardsAccountSettingsDocument> {
    const { data } = await this.client.post('/rewardProgram/insert-permission', document);
    return data;
  }
}

export const rewardsAccountSettingsApi = new RewardsAccountSettingsApi();

