import { useCallback } from 'react';
import { useSelector } from 'react-redux';
import { getAcountNumber } from '../../../hooks/useSelectors';
import { rewardsAccountSettingsService } from '../services';
import { useRewardsAccountSettingsStore } from './useRewardsAccountSettingsStore';

export function useRewardsAccountSettings() {
  const accountId = useSelector(getAcountNumber);

  const { hasRedeemedCashback, isLoading, isError } = useRewardsAccountSettingsStore(
    (state) => state.rewardsAccountSettings
  );

  const { setHasRedeemedCashback, setLoading, setError } = useRewardsAccountSettingsStore(
    (state) => state.rewardsAccountSettingsActions
  );

  const checkHasRedeemed = useCallback(
    async ({ showLoading = false }: { showLoading?: boolean } = {}): Promise<boolean> => {
      if (!accountId) {
        return false;
      }

      if (showLoading) {
        setLoading(true);
      }

      try {
        const hasRedeemed = await rewardsAccountSettingsService.checkHasRedeemedCashback(accountId);
        setHasRedeemedCashback(hasRedeemed);
        return hasRedeemed;
      } catch {
        setError(true);
        return false;
      }
    },
    [accountId, setHasRedeemedCashback, setLoading, setError]
  );

  const markAsRedeemed = useCallback(async (): Promise<boolean> => {
    if (!accountId) {
      return false;
    }

    try {
      await rewardsAccountSettingsService.markCashbackAsRedeemed(accountId);
      setHasRedeemedCashback(true);
      return true;
    } catch {
      return false;
    }
  }, [accountId, setHasRedeemedCashback]);

  return {
    hasRedeemedCashback,
    isLoading,
    isError,
    checkHasRedeemed,
    markAsRedeemed,
  };
}

