import { rewardsAccountSettingsRepository } from '../../../../src/services/rewardsAccountSettings/repository';
import { rewardsAccountSettingsService } from '../../../../src/services/rewardsAccountSettings/services';

jest.mock('../../../../src/services/rewardsAccountSettings/repository');

describe('RewardsAccountSettingsService', () => {
  afterEach(() => {
    jest.clearAllMocks();
  });

  describe('checkHasRedeemedCashback', () => {
    it('should return true if redeemedAtDate is present', async () => {
      (rewardsAccountSettingsRepository.consultAccountSettings as jest.Mock).mockResolvedValue({
        invoiceCashbackRedemption: {
          redeemedAtDate: '2023-10-27T10:00:00Z',
        },
      });

      const result = await rewardsAccountSettingsService.checkHasRedeemedCashback('123');
      expect(result).toBe(true);
    });

    it('should return false if invoiceCashbackRedemption is missing', async () => {
      (rewardsAccountSettingsRepository.consultAccountSettings as jest.Mock).mockResolvedValue({});

      const result = await rewardsAccountSettingsService.checkHasRedeemedCashback('123');
      expect(result).toBe(false);
    });

    it('should return false if redeemedAtDate is missing', async () => {
      (rewardsAccountSettingsRepository.consultAccountSettings as jest.Mock).mockResolvedValue({
        invoiceCashbackRedemption: {},
      });

      const result = await rewardsAccountSettingsService.checkHasRedeemedCashback('123');
      expect(result).toBe(false);
    });

    it('should return false if repository returns null', async () => {
      (rewardsAccountSettingsRepository.consultAccountSettings as jest.Mock).mockResolvedValue(
        null
      );

      const result = await rewardsAccountSettingsService.checkHasRedeemedCashback('123');
      expect(result).toBe(false);
    });
  });

  describe('markCashbackAsRedeemed', () => {
    it('should call upsertAccountSettings with correct document', async () => {
      const accountId = '123';
      const expectedDocument: RewardsAccountSettingsDocument = {
        codigoCliente: accountId,
        status: 1,
        value: {
          invoiceCashbackRedemption: {
            redeemedAtDate: expect.any(String),
          },
        },
      };

      await rewardsAccountSettingsService.markCashbackAsRedeemed(accountId);

      expect(rewardsAccountSettingsRepository.upsertAccountSettings).toHaveBeenCalledWith(
        expectedDocument
      );
    });
  });
});

